"use strict";(self.webpackChunkdocs_site=self.webpackChunkdocs_site||[]).push([["6745"],{5293(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"gettingStartedSidebar":[{"type":"category","label":"Getting Started","collapsed":false,"items":[{"type":"link","href":"/docs/getting-started/intro","label":"Introduction","docId":"getting-started/intro","unlisted":false},{"type":"link","href":"/docs/getting-started/installation","label":"Installation","docId":"getting-started/installation","unlisted":false},{"type":"link","href":"/docs/getting-started/quickstart","label":"Quickstart","docId":"getting-started/quickstart","unlisted":false},{"type":"link","href":"/docs/getting-started/concepts","label":"Core Concepts","docId":"getting-started/concepts","unlisted":false}],"collapsible":true}],"algorithmsSidebar":[{"type":"category","label":"Algorithms","collapsed":false,"items":[{"type":"link","href":"/docs/algorithms/overview","label":"Overview","docId":"algorithms/overview","unlisted":false},{"type":"link","href":"/docs/algorithms/rvq","label":"TurboQuant RVQ","docId":"algorithms/rvq","unlisted":false},{"type":"link","href":"/docs/algorithms/vecinfer","label":"VecInfer","docId":"algorithms/vecinfer","unlisted":false},{"type":"link","href":"/docs/algorithms/ratequant","label":"RateQuant","docId":"algorithms/ratequant","unlisted":false},{"type":"link","href":"/docs/algorithms/spectral","label":"SpectralQuant","docId":"algorithms/spectral","unlisted":false},{"type":"link","href":"/docs/algorithms/rabitq","label":"RaBitQ","docId":"algorithms/rabitq","unlisted":false},{"type":"link","href":"/docs/algorithms/qjl","label":"QJL","docId":"algorithms/qjl","unlisted":false},{"type":"link","href":"/docs/algorithms/polarquant","label":"PolarQuant","docId":"algorithms/polarquant","unlisted":false},{"type":"link","href":"/docs/algorithms/commvq","label":"CommVQ","docId":"algorithms/commvq","unlisted":false},{"type":"link","href":"/docs/algorithms/kivi","label":"KIVI","docId":"algorithms/kivi","unlisted":false}],"collapsible":true}],"guidesSidebar":[{"type":"category","label":"Guides","collapsed":false,"items":[{"type":"link","href":"/docs/guides/mlx-lm-integration","label":"mlx_lm Integration","docId":"guides/mlx-lm-integration","unlisted":false},{"type":"link","href":"/docs/guides/metal-kernels","label":"Metal Kernels","docId":"guides/metal-kernels","unlisted":false},{"type":"link","href":"/docs/guides/calibration","label":"Calibration","docId":"guides/calibration","unlisted":false},{"type":"link","href":"/docs/guides/mixed-precision","label":"Mixed Precision","docId":"guides/mixed-precision","unlisted":false},{"type":"link","href":"/docs/guides/sliding-window","label":"Sliding Window","docId":"guides/sliding-window","unlisted":false},{"type":"link","href":"/docs/guides/observers","label":"Observers","docId":"guides/observers","unlisted":false},{"type":"link","href":"/docs/guides/benchmarking","label":"Benchmarking","docId":"guides/benchmarking","unlisted":false}],"collapsible":true}],"apiSidebar":[{"type":"category","label":"API Reference","collapsed":false,"items":[{"type":"link","href":"/docs/api/cache","label":"Cache","docId":"api/cache","unlisted":false},{"type":"link","href":"/docs/api/quantizers","label":"Quantizers","docId":"api/quantizers","unlisted":false},{"type":"link","href":"/docs/api/allocators","label":"Allocators","docId":"api/allocators","unlisted":false},{"type":"link","href":"/docs/api/spectral-api","label":"SpectralQuant","docId":"api/spectral-api","unlisted":false},{"type":"link","href":"/docs/api/metal-api","label":"Metal Kernels","docId":"api/metal-api","unlisted":false},{"type":"link","href":"/docs/api/observers-api","label":"Observers","docId":"api/observers-api","unlisted":false},{"type":"link","href":"/docs/api/core-api","label":"Core","docId":"api/core-api","unlisted":false},{"type":"link","href":"/docs/api/exceptions-api","label":"Exceptions","docId":"api/exceptions-api","unlisted":false}],"collapsible":true}]},"docs":{"algorithms/commvq":{"id":"algorithms/commvq","title":"CommVQ","description":"CommVQ (Commutative VQ) is designed for models using Rotary Position Embeddings (RoPE). Standard quantization loses positional information because RoPE is applied after keys are written to the cache. CommVQ uses a residual VQ structure that commutes with RoPE \u2014 so position embeddings can be applied to quantized codes without dequantizing first.","sidebar":"algorithmsSidebar"},"algorithms/kivi":{"id":"algorithms/kivi","title":"KIVI","description":"KIVI is VeloxQuant-MLX\'s re-implementation of the field\'s most widely-cited","sidebar":"algorithmsSidebar"},"algorithms/overview":{"id":"algorithms/overview","title":"Algorithm Overview","description":"VeloxQuant-MLX implements nine KV cache compression algorithms. This page helps you pick the right one for your workload.","sidebar":"algorithmsSidebar"},"algorithms/polarquant":{"id":"algorithms/polarquant","title":"PolarQuant","description":"PolarQuant uses recursive polar coordinate decomposition to represent keys as angles rather than Cartesian coordinates. This is particularly effective for models where keys form geometric clusters on a sphere \u2014 a distribution that standard scalar quantizers handle poorly.","sidebar":"algorithmsSidebar"},"algorithms/qjl":{"id":"algorithms/qjl","title":"QJL","description":"QJL (Quantized Johnson-Lindenstrauss) is the simplest algorithm in VeloxQuant-MLX. It uses a random Johnson-Lindenstrauss projection to reduce each key to a 1-bit sign sketch. No calibration, no codebook, no hyperparameters beyond sketch dimension.","sidebar":"algorithmsSidebar"},"algorithms/rabitq":{"id":"algorithms/rabitq","title":"RaBitQ","description":"RaBitQ achieves 1-bit key compression using a randomised Hadamard transform followed by binary sign packing with IVF (Inverted File Index) clustering. It delivers 6\xd7 total KV compression (keys at 1 bit, values at fp16) with zero calibration.","sidebar":"algorithmsSidebar"},"algorithms/ratequant":{"id":"algorithms/ratequant","title":"RateQuant","description":"RateQuant is the highest-accuracy algorithm in VeloxQuant-MLX. It uses a 90-second sensitivity probe to learn which layers need more bits and which can be aggressively compressed \u2014 then allocates a mixed-precision budget via reverse-waterfilling.","sidebar":"algorithmsSidebar"},"algorithms/rvq":{"id":"algorithms/rvq","title":"TurboQuant RVQ","description":"TurboQuant RVQ is the recommended default algorithm in VeloxQuant-MLX. It uses Residual Vector Quantization with analytical codebooks \u2014 no calibration required, works on any model out of the box.","sidebar":"algorithmsSidebar"},"algorithms/spectral":{"id":"algorithms/spectral","title":"SpectralQuant","description":"SpectralQuant uses eigenvector rotation to align the key distribution with the quantizer\'s assumptions. By rotating keys into the PCA basis, it separates high-variance \\"signal\\" dimensions from low-variance \\"noise\\" dimensions and applies separate codebooks to each group \u2014 achieving high fidelity at long context lengths.","sidebar":"algorithmsSidebar"},"algorithms/vecinfer":{"id":"algorithms/vecinfer","title":"VecInfer","description":"VecInfer is VeloxQuant-MLX\'s highest-throughput algorithm. It combines product vector quantization with per-channel smooth scaling and Metal GPU kernels that deliver 13\xd7 faster quantization than naive MLX operations.","sidebar":"algorithmsSidebar"},"api/allocators":{"id":"api/allocators","title":"Allocators API","description":"veloxquant_mlx.allocators","sidebar":"apiSidebar"},"api/cache":{"id":"api/cache","title":"Cache API","description":"veloxquant_mlx.cache","sidebar":"apiSidebar"},"api/core-api":{"id":"api/core-api","title":"Core Abstractions API","description":"veloxquant_mlx.core","sidebar":"apiSidebar"},"api/exceptions-api":{"id":"api/exceptions-api","title":"Exceptions API","description":"veloxquant_mlx.core.exceptions","sidebar":"apiSidebar"},"api/metal-api":{"id":"api/metal-api","title":"Metal Kernels API","description":"veloxquant_mlx.metal","sidebar":"apiSidebar"},"api/observers-api":{"id":"api/observers-api","title":"Observers API","description":"veloxquant_mlx.observers","sidebar":"apiSidebar"},"api/quantizers":{"id":"api/quantizers","title":"Quantizers API","description":"veloxquant_mlx.quantizers","sidebar":"apiSidebar"},"api/spectral-api":{"id":"api/spectral-api","title":"SpectralQuant API","description":"veloxquant_mlx.spectral","sidebar":"apiSidebar"},"changelog":{"id":"changelog","title":"Changelog","description":"All notable changes to VeloxQuant-MLX are documented here."},"getting-started/concepts":{"id":"getting-started/concepts","title":"Core Concepts","description":"This page explains the fundamental ideas behind VeloxQuant-MLX without assuming prior knowledge of quantization theory. If you are already familiar with KV caches and vector quantization, skip to Algorithm Overview.","sidebar":"gettingStartedSidebar"},"getting-started/installation":{"id":"getting-started/installation","title":"Installation","description":"VeloxQuant-MLX uses Metal GPU kernels compiled at runtime. It requires macOS on an Apple M-series chip (M1 or later). Intel Macs and Linux are not supported.","sidebar":"gettingStartedSidebar"},"getting-started/intro":{"id":"getting-started/intro","title":"What is VeloxQuant-MLX?","description":"VeloxQuant-MLX is a production-grade KV cache compression library for Apple Silicon (M-series Macs). It implements nine quantization algorithms that compress the key-value cache used during LLM inference \u2014 reducing peak memory by up to 98% while maintaining near-lossless output quality.","sidebar":"gettingStartedSidebar"},"getting-started/quickstart":{"id":"getting-started/quickstart","title":"5-Minute Quickstart","description":"This guide gets you from a fresh install to compressed LLM inference in five minutes. You will load a model with mlx_lm, attach a TurboQuant RVQ KV cache, generate text, and print memory statistics.","sidebar":"gettingStartedSidebar"},"guides/benchmarking":{"id":"guides/benchmarking","title":"Benchmarking Guide","description":"This guide explains how to use the veloxquant benchmark CLI, interpret results, and reproduce the paper numbers from BENCHMARK_RESULTS.md.","sidebar":"guidesSidebar"},"guides/calibration":{"id":"guides/calibration","title":"Calibration Guide","description":"Some VeloxQuant-MLX algorithms require a calibration step before inference. This guide explains when calibration is needed, how to collect activations, and how to save and reuse calibration artifacts.","sidebar":"guidesSidebar"},"guides/metal-kernels":{"id":"guides/metal-kernels","title":"Metal GPU Kernels","description":"VeloxQuant-MLX compiles nine Metal GPU kernels at runtime using mx.fast.metal_kernel. This guide explains what each kernel does, how they are loaded, performance characteristics, and fallback behaviour.","sidebar":"guidesSidebar"},"guides/mixed-precision":{"id":"guides/mixed-precision","title":"Mixed-Precision Guide","description":"Mixed-precision quantization assigns different bit rates to different layers (or tokens) based on their sensitivity to quantization noise. This achieves better accuracy than uniform quantization at the same average memory footprint.","sidebar":"guidesSidebar"},"guides/mlx-lm-integration":{"id":"guides/mlx-lm-integration","title":"mlx_lm Integration","description":"VeloxQuant-MLX is designed to work as a drop-in extension for mlxlm. This guide covers the three integration patterns: the KVCacheBuilder helper, the mlxlm_patch monkey-patch, and the fused SDPA kernel.","sidebar":"guidesSidebar"},"guides/observers":{"id":"guides/observers","title":"Observers","description":"VeloxQuant-MLX includes four observer classes that attach to a cache or quantizer and collect runtime metrics \u2014 distortion, latency, memory, and key norms. Observers are non-intrusive: they add no overhead to the quantization logic itself.","sidebar":"guidesSidebar"},"guides/sliding-window":{"id":"guides/sliding-window","title":"Sliding Window Cache","description":"SlidingWindowKVCache wraps any VeloxQuant-MLX cache with a token eviction policy. When the sequence length exceeds the window size, old tokens are evicted from the cache, keeping memory bounded regardless of generation length.","sidebar":"guidesSidebar"},"intro":{"id":"intro","title":"VeloxQuant-MLX Documentation","description":""}}}}')}}]);